// Получаем результаты из PostgreSQL
const items = $input.all();

// Получаем данные пользователя из предыдущего узла Extract User Data
const userData = $('Extract User Data').first().json;

// Если истории нет - возвращаем пустой массив
if (items.length === 0) {
  return [{
    json: {
      history: [],
      // Передаем данные пользователя дальше
      userId: userData.userId,
      chatId: userData.chatId,
      userMessage: userData.userMessage,
      userName: userData.userName,
      timestamp: userData.timestamp
    }
  }];
}

// Форматируем историю для AI
const history = items.map(item => ({
  role: item.json.role,
  content: item.json.content,
  created_at: item.json.created_at
}));

return [{
  json: {
    history: history,
    // Передаем данные пользователя дальше
    userId: userData.userId,
    chatId: userData.chatId,
    userMessage: userData.userMessage,
    userName: userData.userName,
    timestamp: userData.timestamp
  }
}];

// Получаем binary data из Read Knowledge Base
const item = $input.first();

if (!item || !item.binary || !item.binary.data) {
  return [{
    json: {
      knowledgeBase: 'База знаний не загружена'
    }
  }];
}

// Правильно извлекаем текст из binary data
// В n8n binary data хранится как Buffer или base64 строка
const binaryData = item.binary.data;
let content;

try {
  if (binaryData.data) {
    // Если есть поле data, это base64
    content = Buffer.from(binaryData.data, 'base64').toString('utf-8');
  } else if (Buffer.isBuffer(binaryData)) {
    // Если это уже Buffer
    content = binaryData.toString('utf-8');
  } else {
    content = 'Не удалось прочитать базу знаний';
  }
} catch (error) {
  content = 'Ошибка чтения базы знаний: ' + error.message;
}

return [{
  json: {
    knowledgeBase: content
  }
}];

// Получаем данные из Merge - он объединяет все в один item
const mergedItem = $input.first().json;

// Merge объединяет объекты, поэтому все поля должны быть на верхнем уровне
const userId = mergedItem.userId;
const chatId = mergedItem.chatId;
const userMessage = mergedItem.userMessage;
const userName = mergedItem.userName;
const timestamp = mergedItem.timestamp;
const knowledge = mergedItem.knowledgeBase || 'База знаний не загружена';
const history = mergedItem.history || [];
const userProfile = mergedItem.userProfile || {};

// Проверяем что данные пользователя найдены
if (!userId || !userMessage) {
  throw new Error('Не найдены данные пользователя. Merged data: ' + JSON.stringify(mergedItem, null, 2));
}

// Реверсируем историю (сначала старые сообщения)
const reversedHistory = Array.isArray(history) ? [...history].reverse() : [];

// Формируем информацию о профиле пользователя
let profileInfo = '';
if (userProfile && Object.keys(userProfile).length > 0) {
  profileInfo = `

=== ПРОФИЛЬ ПОЛЬЗОВАТЕЛЯ ===
Имя: ${userProfile.name || 'не указано'}
Возраст: ${userProfile.age || 'не указано'}
Вес: ${userProfile.weight || 'не указано'} кг
Рост: ${userProfile.height || 'не указано'} см
Цель: ${userProfile.goal || 'не указана'}
=== КОНЕЦ ПРОФИЛЯ ===`;
}

// Формируем массив сообщений для DeepSeek
const messages = [
  {
    role: 'system',
    content: `Ты профессиональный консультант по здоровому питанию и коррекции пищевого поведения.

Твоя задача - помогать клиентам:
1. Понять основы правильного питания и физиологии похудения
2. Разработать индивидуальный план питания
3. Скорректировать пищевое поведение
4. Достичь целей по снижению веса безопасно и эффективно
5. Развенчать мифы о диетах и похудении

Ты используешь только научно обоснованные методы:
- Дробное питание (5-6 раз в день)
- Умеренный дефицит калорий (без голодания)
- Правильное распределение БЖУ
- Учёт гликемического индекса
- Поддержание высокого метаболизма

Будь внимательным, задавай уточняющие вопросы:
- Текущий вес, рост, возраст, пол
- Целевой вес и сроки
- Режим дня и физическая активность
- Пищевые привычки и предпочтения
- Противопоказания и заболевания

Объясняй понятно, с научным обоснованием, с терминами.
Мотивируй, поддерживай, помогай выстроить правильные привычки.

=== НАУЧНАЯ БАЗА ЗНАНИЙ ===
${knowledge}
=== КОНЕЦ БАЗЫ ЗНАНИЙ ===${profileInfo}

⚠️ КРИТИЧЕСКИ ВАЖНО - ОГРАНИЧЕНИЯ TELEGRAM:
- Telegram имеет лимит 4096 символов на сообщение Твой ответ должен быть КРАТКИМ и ЛАКОНИЧНЫМ (старайся укладываться в 2000 символов)
- Говори по делу, без воды

- Отвечай на русском языке
- Структурируй ответ списками и короткими абзацами
- Используй эмодзи
- СТРОГО Используй ТОЛЬКО этот синтаксис для текста:  
  1) Обычный текст
  2) Жирный (2 звездочки) **текст**
  3) Курсив (2 подчеркивания)  __текст__
  4) Ссылки (квадратные и круглые скобки) [текст](ссылка)
  5) Таблицы оборачивай в три обратных апострофа чтобы получить моноширинный текст
`
  }
];

// Добавляем историю (если есть)
reversedHistory.forEach(msg => {
  messages.push({
    role: msg.role,
    content: msg.content
  });
});

// Добавляем текущее сообщение
messages.push({
  role: 'user',
  content: userMessage
});

return [
  {
    json: {
      messages: messages,
      userId: userId,
      chatId: chatId,
      userName: userName,
      userMessage: userMessage,
      timestamp: timestamp
    }
  }
];

// Получаем результаты из PostgreSQL
const items = $input.all();
const userData = $('Extract User Data').first().json;

// Если профиля нет - возвращаем пустой объект
if (items.length === 0) {
  return [{
    json: {
      userProfile: {},
      userId: userData.userId,
      chatId: userData.chatId,
      userMessage: userData.userMessage,
      userName: userData.userName,
      timestamp: userData.timestamp
    }
  }];
}

// Берем первую запись
const profile = items[0].json;

return [{
  json: {
    userProfile: {
      name: profile.name,
      age: profile.age,
      weight: profile.weight,
      height: profile.height,
      goal: profile.goal
    },
    userId: userData.userId,
    chatId: userData.chatId,
    userMessage: userData.userMessage,
    userName: userData.userName,
    timestamp: userData.timestamp
  }
}];

const aiResponse = $input.first().json;
const context = $('Build AI Context').first().json;

// Извлекаем ответ от DeepSeek
const response = aiResponse.choices[0].message.content;

return [
  {
    json: {
      userId: context.userId,
      chatId: context.chatId,
      userName: context.userName,
      userMessage: context.userMessage,
      response: response,
      timestamp: context.timestamp
    }
  }
];

const data = $input.first().json;
const now = new Date().toISOString();

// Создаем 2 записи для PostgreSQL
return [
  {
    json: {
      user_id: data.userId,
      role: 'user',
      content: data.userMessage,
      created_at: data.timestamp
    }
  },
  {
    json: {
      user_id: data.userId,
      role: 'assistant',
      content: data.response,
      created_at: now
    }
  }
];
